mapper.select:
SELECT id, create_date, res_model, res_id, content, author_name, user_id
FROM ir_note


        AND (
            content ILIKE CONCAT('%', #{query.keyword}, '%')
            OR author_name ILIKE CONCAT('%', #{query.keyword}, '%')
        )


        AND res_model = #{query.resModel}


        AND res_id = #{query.resId}


ORDER BY create_date DESC, id DESC
